const { BREP } = api;

// Canopy - the disc on the ceiling
const canopy = BREP.label(
  BREP.cone(15, 18, 4).translate([0, 0, 56]),
  'canopy'
);

// Vertical chain - a thin cylinder for reliability (torus stack tessellation was fragile)
const chain = BREP.label(
  BREP.cylinder(0.7, 30).translate([0, 0, 26]),
  'chain'
);

// Central hub - cone widening (rTop=12 wide at z=8, rBottom=4 narrow at z=0)
// translated to z=24 puts the narrow base at z=24 and wide top at z=32.
const hub = BREP.label(
  BREP.cone(4, 12, 8).translate([0, 0, 24]),
  'hub'
);

// One arm - sticks out from x=2 to x=26 so arms don't cross at origin.
// Center-of-box X = 14, length 24 in X, 1.5 in Y, 1.5 in Z.
const armSeed = BREP.box([24, 1.5, 1.5]).translate([14, 0, 22]);
const arms = BREP.label(
  BREP.circularPattern(armSeed, 5, { radius: 0, axis: [0, 0, 1], angle: 360 }),
  'arm'
);

// Bulbs - sphere at end of each arm (arm tip is at x=26).
const bulbSeed = BREP.sphere(3).translate([26, 0, 22]);
const bulbs = BREP.label(
  BREP.circularPattern(bulbSeed, 5, { radius: 0, axis: [0, 0, 1], angle: 360 }),
  'bulb'
);

// Center finial - small decorative sphere below the hub
const finial = BREP.label(
  BREP.sphere(2).translate([0, 0, 20]),
  'finial'
);

return BREP.fuseAll([canopy, chain, hub, arms, bulbs, finial]);
